// MAP (Mutual Action Plans) data — stored in localStorage, edit via MAP Hub
function getMaps() {
  try { return JSON.parse(localStorage.getItem('hub_maps') || '[]'); } catch(e) { return []; }
}
function saveMaps(maps) {
  localStorage.setItem('hub_maps', JSON.stringify(maps));
}
